const nowKarachi = $now.setZone('Asia/Karachi');
const yesterday = nowKarachi.minus({ days: 1 });
const dateStr = yesterday.toFormat('yyyy-MM-dd');
const fromISO = yesterday.startOf('day').toUTC().toISO();
const toISO = yesterday.endOf('day').toUTC().toISO();
return [{ json: { dateStr, fromISO, toISO } }];

// FIXED: trims Parameter names before using them as config keys.
// A stray leading/trailing space on a Config row (e.g. " Reconciliation_Date_Override")
// silently breaks any downstream lookup by exact key name (config.Reconciliation_Date_Override
// would be undefined even though the row exists), with no error thrown anywhere.
const config = {};
for (const item of items) {
  const p = String(item.json.Parameter || '').trim();
  let v = item.json.Value;
  if (p && (v === 'TRUE' || v === 'FALSE')) v = (v === 'TRUE');
  if (p) config[p] = v;
}
return [{ json: { config } }];

// Applies Config!Reconciliation_Date_Override if present (test/demo mode),
// otherwise uses the real "yesterday" computed upstream. Leave the Config
// row blank/absent for production so it defaults to real yesterday.
//
// FIXED (previous version only overrode dateStr and left fromISO/toISO
// pointing at the real-yesterday window, so the Traccar GPS query and the
// form-matching logic silently checked two different dates). Now both are
// rebuilt together from the override, in Asia/Karachi (+05:00, no DST).
const data = items[0].json;
const active = data.masterTrucks.filter(t => String(t.Active_Flag).toUpperCase() === 'TRUE');

const override = data.config && data.config.Reconciliation_Date_Override;
const overrideStr = (override && String(override).trim() !== '') ? String(override).trim() : null;

let dateWindow;
if (overrideStr) {
  dateWindow = {
    dateStr: overrideStr,
    fromISO: `${overrideStr}T00:00:00+05:00`,
    toISO: `${overrideStr}T23:59:59+05:00`
  };
} else {
  dateWindow = data.dateWindow;
}

return active.map(truck => ({ json: {
  truck,
  formResponses: data.formResponses,
  driverLookup: data.driverLookup,
  config: data.config,
  dateWindow
} }));

const truckCtx = $('Loop Trucks').item.json;
const body = $json.body || $json;
const trips = Array.isArray(body) ? body : [];
const norm = (s) => String(s || '').trim().toLowerCase();
const deviceName = truckCtx.truck.Traccar_Device_Name;
const dateStr = truckCtx.dateWindow.dateStr;
const cfg = truckCtx.config;

// PATCHED: robust date parser. Google Sheets can hand back dates in ISO
// (2026-07-02), US slash format (7/2/2026), or a full datetime string,
// depending on cell formatting/locale. The old code did
// String(f['Trip_Start_Date']).slice(0,10) === dateStr, which only works
// for ISO strings and silently fails (NO_FORM_MATCH) on anything else.
function toDateStr(raw) {
  if (raw === null || raw === undefined || raw === '') return null;
  const s = String(raw).trim();
  // Already ISO-like (2026-07-02 or 2026-07-02T...)
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);
  const d = new Date(s);
  if (isNaN(d.getTime())) return null;
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd}`;
}

const realTrips = trips.filter(t => t.distance > 1000);
const totalDistance = realTrips.reduce((sum, t) => sum + t.distance, 0);
const totalFuel = realTrips.reduce((sum, t) => sum + (t.spentFuel || 0), 0);
const totalDuration = realTrips.reduce((sum, t) => sum + t.duration, 0);
const aggregatedTrip = realTrips.length ? {
  distance: totalDistance,
  spentFuel: totalFuel,
  startTime: realTrips[0].startTime,
  endTime: realTrips[realTrips.length - 1].endTime,
  duration: totalDuration,
  driverUniqueId: realTrips[0].driverUniqueId
} : null;

if (!aggregatedTrip) {
  return [{ json: { matched: false, reason: 'NO_TRACCAR_TRIP', truck: truckCtx.truck, dateStr } }];
}

const form = truckCtx.formResponses.find(f =>
  norm(f['Assigned_Truck_Registration']) === norm(deviceName) &&
  toDateStr(f['Trip_Start_Date']) === dateStr
);

if (!form) {
  return [{ json: { matched: false, reason: 'NO_FORM_MATCH', truck: truckCtx.truck, dateStr } }];
}

const driverEntry = truckCtx.driverLookup.find(d => d.Driver_ID === form.Driver_ID) || null;

const GPS_Km = aggregatedTrip.distance / 1000;
const Claimed_Km = Number(form.Claimed_Trip_Distance_Km);
const Variance_Km = Claimed_Km - GPS_Km;

const efficiency = (truckCtx.truck.Fuel_Efficiency_KmL && truckCtx.truck.Fuel_Efficiency_KmL !== '')
  ? Number(truckCtx.truck.Fuel_Efficiency_KmL)
  : Number(cfg.Default_Truck_Fuel_Efficiency_KmL);

const GPS_Fuel_Theoretical_Litres = GPS_Km / efficiency;
const Traccar_Fuel_Consumed_Litres = (aggregatedTrip.spentFuel !== undefined && aggregatedTrip.spentFuel !== null)
  ? aggregatedTrip.spentFuel
  : null;
const Claimed_Fuel_Litres = Number(form.Fuel_Added_This_Trip_Litres);
const Fuel_Variance_Litres = (Traccar_Fuel_Consumed_Litres !== null)
  ? Claimed_Fuel_Litres - Traccar_Fuel_Consumed_Litres
  : null;
const Fuel_variance_pct = (Traccar_Fuel_Consumed_Litres && Traccar_Fuel_Consumed_Litres !== 0)
  ? (Fuel_Variance_Litres / Traccar_Fuel_Consumed_Litres) * 100
  : null;

const Variance_Percent = GPS_Km !== 0 ? (Variance_Km / GPS_Km) * 100 : null;
const Variance_PKR = Variance_Km * (Number(cfg.Fuel_Cost_Per_Litre) / efficiency);

let Flag_Colour = 'GREY_UNMATCHED';
if (Variance_Percent !== null) {
  const absPct = Math.abs(Variance_Percent);
  if (absPct <= Number(cfg.Amber_Threshold_Pct)) Flag_Colour = 'GREEN';
  else if (absPct <= Number(cfg.Red_Threshold_Pct)) Flag_Colour = 'AMBER';
  else Flag_Colour = 'RED';
}

const Trip_Duration_Minutes = aggregatedTrip.duration / 60;

const demoMode = String(cfg.Demo_Mode).toUpperCase() === 'TRUE' || cfg.Demo_Mode === true;
const GPS_Start_Odometer_Km = demoMode ? Number(form.Start_Odometer_Reading_Km) : null;
const GPS_End_Odometer_Km = demoMode ? Number(form.End_Odometer_Reading_Km) : null;
const Idle_Minutes = demoMode ? Math.round(Trip_Duration_Minutes * Number(cfg.Demo_Idle_Time_Pct_Placeholder)) : null;

const High_Variance_Unmatched_Alert = (Flag_Colour === 'GREY_UNMATCHED') ? false : (Math.abs(Variance_Percent) > Number(cfg.Red_Threshold_Pct));

const Reconciliation_Key = `${truckCtx.truck.Truck_ID}|${dateStr}|${form.Driver_ID}`;
const Idempotency_Key = `${truckCtx.truck.Truck_ID}|${aggregatedTrip.startTime}|${form.Driver_ID}|${GPS_Km}`;

return [{ json: {
  matched: true,
  truck: truckCtx.truck,
  dateStr,
  trip: aggregatedTrip,
  form,
  driverEntry,
  calc: {
    Trip_ID: `${truckCtx.truck.Truck_ID}_${dateStr}`,
    Trip_Date: dateStr,
    Truck_ID: truckCtx.truck.Truck_ID,
    Registration: truckCtx.truck.Registration,
    Driver_ID: form.Driver_ID,
    Traccar_Driver_UniqueId: (driverEntry && driverEntry.Mapping_Status === 'CONFIRMED') ? driverEntry.Traccar_Driver_UniqueId : '',
    Route_ID: form.Trip_Route,
    Trip_Start_Timestamp: aggregatedTrip.startTime,
    Trip_End_Timestamp: aggregatedTrip.endTime,
    GPS_Km,
    GPS_Km_Source: 'TRIPS_REPORT_DISTANCE',
    GPS_Km_Source_Meters: aggregatedTrip.distance,
    GPS_Start_Odometer_Km,
    GPS_End_Odometer_Km,
    Claimed_Km,
    Variance_Km,
    GPS_Fuel_Theoretical_Litres,
    Traccar_Fuel_Consumed_Litres,
    Claimed_Fuel_Litres,
    Fuel_Variance_Litres,
    Variance_Percent,
    Variance_PKR,
    Flag_Colour,
    Idle_Minutes,
    Trip_Duration_Minutes,
    GPS_Source: 'TRACCAR',
    Form_Submission_Time: form.Timestamp,
    Reconciliation_Key,
    Idempotency_Key,
    Fuel_variance_pct,
    Reconciliation_Status: 'MATCHED',
    High_Variance_Unmatched_Alert
  }
} }];

// FIXED (two bugs):
// 1) 'items' inside this Code node is the output of the node feeding it directly
//    (Read DLQ_Log For Count), NOT Read Trip_Data For Count. The previous version
//    did `const tripRows = items` and filtered DLQ rows for a Trip_Date field they
//    don't have -> always 0 matched, regardless of what Trip_Data actually contained.
//    Now explicitly pulled by node name.
// 2) formsForToday used a naive slice(0,10) on Trip_Start_Date, which is stored as
//    M/D/YYYY text (e.g. '7/2/2026'), not ISO -> always failed to match. Now uses the
//    same robust date parser as Match Trip to Form Response.
function toDateStr(raw) {
  if (raw === null || raw === undefined || raw === '') return null;
  const s = String(raw).trim();
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);
  const d = new Date(s);
  if (isNaN(d.getTime())) return null;
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd}`;
}

const dateWindow = $('Filter Active Trucks + To Items').first().json.dateWindow;
const activeTrucks = $('Filter Active Trucks + To Items').all();
const formResponsesWrap = $('Wrap Form_Responses').first().json.formResponses;

const tripRows = $('Read Trip_Data For Count').all();
const tripsForToday = tripRows.filter(i => toDateStr(i.json.Trip_Date) === dateWindow.dateStr);

const dlqRows = $('Read DLQ_Log For Count').all();
const dlqForThisRun = dlqRows.filter(i => String(i.json.Execution_ID) === String($execution.id));

const formsForToday = formResponsesWrap.filter(f => toDateStr(f.Trip_Start_Date) === dateWindow.dateStr);

const summary = {
  Execution_ID: $execution.id,
  Workflow_Name: 'Fuel_Fraud_Audit_Daily_Reconcile',
  Started_At: $execution.startedAt ? new Date($execution.startedAt).toISOString() : new Date().toISOString(),
  Ended_At: new Date().toISOString(),
  Run_Status: dlqForThisRun.length === 0 ? 'SUCCESS' : 'PARTIAL_SUCCESS',
  Date_Window_Start: dateWindow.fromISO,
  Date_Window_End: dateWindow.toISO,
  Trips_Read: activeTrucks.length,
  Trips_Report_Rows_Read: activeTrucks.length,
  Notes_Endpoint_Calls: `${activeTrucks.length} calls to /api/reports/trips (one per active truck)`,
  Forms_Read: formsForToday.length,
  Trips_Matched: tripsForToday.length,
  Rows_Appended: tripsForToday.length,
  DLQ_Count: dlqForThisRun.length,
  Notes: dlqForThisRun.length > 0
    ? `${dlqForThisRun.length} row(s) sent to DLQ_Log this run - see Error_Category there for detail.`
    : 'Clean run, no DLQ entries.'
};

return [{ json: summary }];

// Splits the raw Traccar /reports/trips response into one item per trip,
// mapped to the Traccar_Trips_Raw schema, for audit logging purposes only.
// This runs in PARALLEL to the main matching logic below -- it never
// modifies or delays the existing Match Trip to Form Response path.
const truckCtx = $('Loop Trucks').item.json;
const body = $json.body || $json;
const trips = Array.isArray(body) ? body : [];

const truck = truckCtx.truck;
const dateWindow = truckCtx.dateWindow;
const nowIso = $now.toISO();

if (trips.length === 0) {
  return [];
}

return trips.map((t, idx) => ({
  json: {
    Raw_Record_ID: `RAW-${$now.toFormat('yyyyMMddHHmmss')}-${truck.Traccar_Device_Id}-${idx}`,
    Ingested_At: nowIso,
    Provider: 'TRACCAR',
    Traccar_Trip_Ref: `${t.startPositionId ?? ''}-${t.endPositionId ?? ''}`,
    Device_Id: truck.Traccar_Device_Id,
    Registration: truck.Registration || truck.Traccar_Device_Name || '',
    Traccar_Driver_UniqueId: t.driverUniqueId || '',
    Start_Timestamp: t.startTime || '',
    End_Timestamp: t.endTime || '',
    Trip_Distance_Meters: t.distance ?? 0,
    Spent_Fuel_Litres: t.spentFuel ?? 0,
    Duration_Seconds: t.duration ? Math.round(t.duration / 1000) : 0,
    Max_Speed_Knots: t.maxSpeed ?? 0,
    Average_Speed_Knots: t.averageSpeed ?? 0,
    Start_Address: t.startAddress || '',
    End_Address: t.endAddress || '',
    Source_Date_Window_Start: dateWindow.fromISO || '',
    Source_Date_Window_End: dateWindow.toISO || '',
    Raw_JSON: JSON.stringify(t).slice(0, 45000)
  }
}));
